SELECT lp.* FROM learning_progress lp LEFT JOIN user u ON lp.user_id=u.id AND u.deleted=0
WHERE lp.deleted=0
AND u.dept_id=#{deptId}
AND lp.user_id=#{userId}
AND lp.course_id=#{courseId}
ORDER BY lp.id DESC LIMIT #{offset()},#{pageSize}

SELECT COUNT(1) FROM learning_progress lp LEFT JOIN user u ON lp.user_id=u.id AND u.deleted=0
WHERE lp.deleted=0
AND u.dept_id=#{deptId}
AND lp.user_id=#{userId}
AND lp.course_id=#{courseId}
